import React, { useState, useMemo, useEffect } from "react";

const DATA = {"nodes": [{"id": "n_root", "parent_id": null, "evidence_quality": "well-evidenced", "label": "What does the evidence show about ultra-processed foods and health \u2014 and is it the processing, or the nutrients the processing carries?", "children": ["n_concept", "n_assoc", "n_cause", "n_policy"], "role": "topic", "question": {"research": "What does the evidence show about ultra-processed foods and health \u2014 and is it the processing, or the nutrients the processing carries?", "simple": "Are ultra-processed foods bad for you?"}, "depends_on": {"research": "'Bad for you' is not one measurable quantity. The literature separately measures whether the ultra-processed (NOVA) category is even reliably definable, the size of the observational disease association, whether that association is about processing or about the nutrients and lifestyle it travels with, whether controlled trials show processing itself causes harm, and what ultra-processed-food policy measurably changes \u2014 with sharply different degrees of consensus. Public and political debate routinely lets confidence on one of these stand in for all of them; this tree exists to keep them apart.", "simple": "There's no single 'is it bad' score. Whether 'ultra-processed' even means one clear thing, whether heavy eaters get sicker, whether it's the processing or just the sugar and salt, whether careful experiments show processing itself causes overeating, and whether food policies work are different questions with different-quality evidence. Pick one."}, "coverage_note": "Authored dimensions: the validity of the category, the observational association, whether processing or nutrients drive it, controlled-trial causal evidence, and restriction/labelling policy. DELIBERATELY NOT COVERED (invisible to this tool): 'food addiction' as a clinical construct; individual additives and their toxicology (emulsifiers, nitrites, non-sugar sweeteners) as separate claims; environmental/food-system sustainability; children and adolescents as a separate population (this map is adult-focused, where the RCT and cohort evidence sits); eating-disorder outcomes; industry political economy and marketing-to-children beyond what a policy finding carries; and whether restricting ultra-processed food is JUSTIFIED all things considered \u2014 a values question this tool records no verdict on. Absence is a scope choice, not evidence of no effect. Two definitional boundaries: 'processed' is not 'ultra-processed' (NOVA group 3 vs group 4), and nutrient-targeted policy (e.g. sugar labels) is not processing-targeted policy \u2014 findings must not silently swap them.", "scored": false, "evidence_caveats": []}, {"id": "n_concept", "parent_id": "n_root", "evidence_quality": "thin", "label": "Is 'ultra-processed' a valid, usable category \u2014 or a label that can't be applied consistently and adds little beyond known nutrients?", "children": ["n_concept_reliable", "n_concept_beyond"], "role": "dimension", "question": {"research": "Is 'ultra-processed' a valid, usable category \u2014 or a label that can't be applied consistently and adds little beyond known nutrients?", "simple": "Does 'ultra-processed' even mean one clear thing \u2014 and does it tell us anything sugar, salt and fat don't already?"}, "depends_on": {"research": "Two separable questions: whether trained raters even assign the same foods to the NOVA 'ultra-processed' group (reliability), and whether the category predicts harm beyond what conventional nutrient profiling already captures (added value). A category can be unreliable yet still track something real, or reliable yet redundant with nutrients \u2014 the two failures are different and are scored separately.", "simple": "First: if you give the same food to different experts, do they agree it's 'ultra-processed'? Second: even if they agree, does the label warn you of anything that checking sugar, salt and fat wouldn't? Those are two different ways the category could be weak."}, "coverage_note": "Covers the classification's reliability and its added value over nutrient profiling. Does not adjudicate the NOVA system's four-group structure as a whole, nor rival processing-classification schemes (SIGA, IARC/IFIC) except where a finding carries them.", "scored": false, "evidence_caveats": ["classification validity is itself contested \u2014 read the association leaves in that light"]}, {"id": "n_concept_reliable", "parent_id": "n_concept", "evidence_quality": "thin", "label": "Can the NOVA 'ultra-processed' category be applied consistently by different classifiers?", "children": [], "role": "leaf", "question": {"research": "Can the NOVA 'ultra-processed' category be applied consistently by different classifiers?", "simple": "Do different experts agree on what counts as 'ultra-processed'?"}, "claim_evaluated": {"research": "The NOVA 'ultra-processed' category can be applied consistently \u2014 different trained classifiers reliably assign the same foods to the same group.", "simple": "'Ultra-processed' is defined clearly enough that different experts sort foods into it the same way."}, "depends_on": {"research": "Reliability is measured, not asserted: inter-rater agreement statistics (e.g. Fleiss' kappa) on classifying the same food lists. Notably, agreement in the main reliability study stayed low even when full ingredient information was available \u2014 so it is not simply a fixable data-access problem. Low reliability undercuts what any pooled UPF\u2013outcome association can mean, because the exposure is being measured inconsistently.", "simple": "This is testable: give many experts the same foods and see how often they agree. In the main test, agreement stayed poor even when they could see the full ingredient list \u2014 so it's not just a matter of giving them more information. If experts can't agree what's 'ultra-processed', it's hard to trust studies that lump it all together."}, "scored": true, "evidence_caveats": ["rests on a single dedicated reliability study (Braesco 2022)", "no qualifying FOR located \u2014 one-sided"]}, {"id": "n_concept_beyond", "parent_id": "n_concept", "evidence_quality": "well-evidenced", "label": "Does ultra-processed status predict harm beyond what conventional nutrient profiling already captures?", "children": [], "role": "leaf", "question": {"research": "Does ultra-processed status predict harm beyond what conventional nutrient profiling already captures?", "simple": "Does the 'ultra-processed' label warn of anything that checking sugar, salt and fat doesn't?"}, "claim_evaluated": {"research": "Ultra-processed status carries information about health risk over and above conventional nutrient profiling (sugar, salt, saturated fat, energy density) \u2014 the processing dimension adds predictive value.", "simple": "Knowing a food is 'ultra-processed' tells you something about health risk beyond what its sugar, salt and fat already tell you."}, "depends_on": {"research": "Depends on whether UPF\u2013outcome associations persist once nutrient composition or diet-quality indices are adjusted for. Persistence supports added value; full attenuation implies the label is a proxy for nutrients already measurable. This is the added-value framing; the closely related n_assoc_confound leaf asks the same statistical question from the association's side \u2014 they are scored separately because 'the concept is redundant' and 'this particular association is confounded' are different claims.", "simple": "If the 'ultra-processed' link to disease survives after you account for sugar, salt and fat, the label is adding something. If it vanishes, the label was just standing in for nutrients you could already measure."}, "scored": true, "evidence_caveats": ["exposure and diet-quality adjustment both derive from self-reported diet \u2014 over- or under-adjustment cannot be excluded"]}, {"id": "n_assoc", "parent_id": "n_root", "evidence_quality": "well-evidenced", "label": "How is ultra-processed food consumption related to disease \u2014 how large, and is it the processing?", "children": ["n_assoc_magnitude", "n_assoc_confound", "n_assoc_subgroup"], "role": "dimension", "question": {"research": "How is ultra-processed food consumption related to disease \u2014 how large, and is it the processing?", "simple": "Do people who eat more ultra-processed food get sicker \u2014 and is the food itself the reason?"}, "depends_on": {"research": "Depends on WHICH question (does an association exist and how large, vs. does it survive adjustment for nutrients and confounders, vs. is it uniform across UPF types), and on measurement (almost all evidence is self-reported diet via food-frequency questionnaires, with residual confounding and healthy-user bias live throughout).", "simple": "Depends what you're asking (is there a link, how big, does it hold up when you account for a bad diet generally, and is every ultra-processed food equally to blame) \u2014 and on the fact that nearly all of it rests on people reporting their own eating, which is error-prone."}, "coverage_note": "Captures the magnitude of the observational association, whether it reflects processing after adjustment, and whether it is concentrated in UPF subgroups. Cause-in-the-controlled-trial sense lives under n_cause; the classification's validity lives under n_concept.", "scored": false, "evidence_caveats": ["near-entirely observational, self-reported diet (FFQ) throughout \u2014 residual confounding and healthy-user bias are live"]}, {"id": "n_assoc_magnitude", "parent_id": "n_assoc", "evidence_quality": "well-evidenced", "label": "Is higher ultra-processed food consumption associated with worse health outcomes at a meaningful magnitude?", "children": [], "role": "leaf", "question": {"research": "Is higher ultra-processed food consumption associated with worse health outcomes at a meaningful magnitude?", "simple": "Do people who eat the most ultra-processed food have clearly worse health?"}, "claim_evaluated": {"research": "Higher ultra-processed food consumption is associated with worse health outcomes (all-cause mortality, cardiovascular disease, type-2 diabetes, obesity) at a magnitude that is practically meaningful, not trivially small.", "simple": "People who eat the most ultra-processed food have noticeably worse health \u2014 the link is big enough to matter."}, "depends_on": {"research": "The existence of a broad association is not seriously disputed; the live questions are magnitude and interpretation. Umbrella-level syntheses report associations across dozens of outcomes, but individual well-controlled cohorts report modest hazard ratios (e.g. ~+4% all-cause mortality, top vs bottom quartile). Findings must report the number, not the adjective.", "simple": "Almost everyone agrees there's SOME link across many diseases. The fight is how big \u2014 some careful studies find only a few percent higher risk. Look at the actual number, not the headline."}, "scored": true, "evidence_caveats": ["observational \u2014 causal interpretation is not licensed", "graded evidence tiers reflect statistical strength/consistency, not causation"]}, {"id": "n_assoc_confound", "parent_id": "n_assoc", "evidence_quality": "well-evidenced", "label": "Does the association reflect processing itself, rather than being explained by nutrients and confounding?", "children": [], "role": "leaf", "question": {"research": "Does the association reflect processing itself, rather than being explained by nutrients and confounding?", "simple": "Is it the processing that's harmful \u2014 or just that ultra-processed diets are high in sugar, salt and fat and go with unhealthy lifestyles?"}, "claim_evaluated": {"research": "The observed ultra-processed-food\u2013disease association reflects a processing effect that survives adjustment for nutrient quality and confounders \u2014 it is not fully explained by the sugar/salt/fat/energy-density of these foods or by healthy-user bias.", "simple": "The harm from ultra-processed food is really about the processing \u2014 it doesn't disappear once you account for the fact that these diets are also high in sugar, salt and fat and common among people with less healthy lifestyles."}, "depends_on": {"research": "The pivotal and most genuinely two-sided empirical leaf. Reviews disagree: some report associations 'remain significant and unchanged in magnitude' after diet-quality adjustment; others (including a large 2024 cohort) find the association substantially attenuates once overall dietary quality is controlled. Because the exposure and confounders are both derived from self-reported diet, residual confounding cannot be excluded. Adjustment can also over-control if nutrients are on the causal pathway.", "simple": "This is the crux, and it's genuinely disputed. Some reviews say the link barely changes when you account for a poor diet; a big 2024 study says it fades a lot. And because everything comes from people reporting their own eating, you can never fully rule out that something else about heavy eaters explains it."}, "scored": true, "evidence_caveats": ["the pivotal processing-vs-nutrients dispute \u2014 carried live in both directions", "adjustment can over-control if nutrients lie on the causal pathway of processing"]}, {"id": "n_assoc_subgroup", "parent_id": "n_assoc", "evidence_quality": "thin", "label": "Are harms concentrated in specific ultra-processed subgroups rather than uniform across all ultra-processed food?", "children": [], "role": "leaf", "question": {"research": "Are harms concentrated in specific ultra-processed subgroups rather than uniform across all ultra-processed food?", "simple": "Is it certain ultra-processed foods (like processed meat and fizzy drinks) most linked to disease \u2014 not all of them equally?"}, "claim_evaluated": {"research": "The health harms of ultra-processed food are concentrated in specific subgroups (notably processed meats and sugar-sweetened beverages) rather than spread uniformly across all ultra-processed foods.", "simple": "The link to disease is concentrated in particular ultra-processed foods \u2014 processed meats, sugary drinks \u2014 while many others show no clear link."}, "depends_on": {"research": "If true, a total-UPF exposure average mixes harmful, neutral, and possibly protective subgroups, so the aggregate understates the worst categories and overstates the benign ones \u2014 which changes what a single 'ultra-processed' policy target would capture. Depends on the subgroup breakdown within cohorts; independent corroboration across cohorts is the test of whether the pattern is robust.", "simple": "If some ultra-processed foods are linked to harm and others aren't, then lumping them together as one number is misleading \u2014 and a policy that treats all ultra-processed food the same hits the unlinked ones too. The test is whether different studies find the same bad-and-neutral split."}, "scored": true, "evidence_caveats": ["subgroup breakdown comes from a single cohort", "'no significant association' for a subgroup is not evidence of safety", "no independent AGAINST located \u2014 one-sided"]}, {"id": "n_cause", "parent_id": "n_root", "evidence_quality": "well-evidenced", "label": "Do controlled trials show ultra-processing itself causes harm, independent of nutrients?", "children": ["n_cause_intake"], "role": "dimension", "question": {"research": "Do controlled trials show ultra-processing itself causes harm, independent of nutrients?", "simple": "When you actually run the experiment, does ultra-processing itself cause harm?"}, "depends_on": {"research": "Controlled-feeding trials can hold nutrient composition roughly constant and vary processing, isolating a processing effect that observational designs cannot. But such trials are few, small, and short, use highly controlled or metabolic-ward settings, and their mechanism (energy density, hyper-palatability, eating rate) is debated \u2014 a real intake effect does not by itself pin the causal lever on 'processing' as opposed to texture and energy density that nutrient policy could also target.", "simple": "Experiments that feed people matched diets and change only the processing can show cause in a way surveys can't. But there are only a few, they're small and short, and even when they find an effect, researchers argue about WHY \u2014 is it the processing, or that these foods are soft, calorie-dense and easy to eat fast?"}, "coverage_note": "Only the energy-intake / weight causal claim is scored \u2014 it is where controlled trials exist. Longer-term disease endpoints (CVD, cancer) cannot be tested in feeding trials and are covered observationally under n_assoc. Additive-specific mechanisms are out of scope (see root coverage note).", "scored": false, "evidence_caveats": ["only four qualifying RCTs, small and short \u2014 generalisability limited"]}, {"id": "n_cause_intake", "parent_id": "n_cause", "evidence_quality": "well-evidenced", "label": "Do ultra-processed diets cause excess energy intake or weight gain independent of nutrient composition?", "children": [], "role": "leaf", "question": {"research": "Do ultra-processed diets cause excess energy intake or weight gain independent of nutrient composition?", "simple": "In controlled experiments, do people eat more and gain weight on an ultra-processed diet even when the nutrients are matched?"}, "claim_evaluated": {"research": "Ultra-processed diets cause excess energy intake and weight gain relative to less-processed diets, independent of nutrient composition (calories presented, macronutrients, sugar, sodium, fibre matched).", "simple": "When diets are matched for nutrients and only the processing differs, people eat more and gain weight on the ultra-processed one."}, "depends_on": {"research": "Depends on the trial: the landmark inpatient RCT matched presented calories, energy density, macronutrients, sugar, sodium and fibre and still found ~+500 kcal/day; a 2025 outpatient crossover found more weight loss on minimally-processed diets following healthy-eating guidance. Both are small; the second drew formal published critiques. Whether the effect generalises beyond metabolic-ward or motivated-volunteer settings, and whether the operative lever is 'processing' or energy density and eating rate, are open.", "simple": "The strongest study locked people in a research ward, matched the nutrients, and still saw ~500 extra calories a day on the ultra-processed diet. A 2025 study found more weight loss on the less-processed diet \u2014 but it's small and was formally criticised. Whether this holds in normal life, and whether it's really 'processing' versus just calorie-dense, easy-to-eat food, is unsettled."}, "scored": true, "evidence_caveats": ["metabolic-ward / motivated-volunteer settings", "the causal lever (processing vs energy density / eating rate) is contested", "fast-moving: Re-check the Nature Medicine critique/reply thread on Dicken 2025 before republish \u2014 the dispute was active at authoring time."]}, {"id": "n_policy", "parent_id": "n_root", "evidence_quality": "well-evidenced", "label": "What would ultra-processed-food policy \u2014 dietary guidance, warning labels \u2014 measurably change?", "children": ["n_policy_guidance", "n_policy_labels"], "role": "dimension", "question": {"research": "What would ultra-processed-food policy \u2014 dietary guidance, warning labels \u2014 measurably change?", "simple": "Would ultra-processed-food rules and labels actually do anything?"}, "depends_on": {"research": "Depends on the question: whether official bodies judge the evidence strong enough to issue UPF-specific guidance (an evidence-sufficiency judgement authorities currently split on), versus whether a given instrument (front-of-pack warning labels) measurably changes behaviour. Crucially, the strongest label evidence targets NUTRIENTS, not the processing category \u2014 so it speaks to nutrient-based policy and only by assumption to UPF-specific policy.", "simple": "Two different things: do the official expert panels think the evidence is good enough to tell people to cut ultra-processed food (they disagree), and do warning labels actually change what people buy (there's real evidence they do \u2014 but those labels flag sugar and salt, not 'ultra-processed', which isn't the same target)."}, "coverage_note": "Covers evidence-sufficiency for UPF-specific guidance and the measured effect of warning labels. Whether such policies are JUSTIFIED (autonomy, cost, equity, industry effects) is a values question outside this map. Taxes, marketing bans, and reformulation mandates are visible only where a cited label study bundles them.", "scored": false, "evidence_caveats": ["fast-moving: a US federal UPF definition is due 2026 and may move these findings"]}, {"id": "n_policy_guidance", "parent_id": "n_policy", "evidence_quality": "well-evidenced", "label": "Is the evidence strong enough to justify ultra-processed-specific dietary guidance?", "children": [], "role": "leaf", "question": {"research": "Is the evidence strong enough to justify ultra-processed-specific dietary guidance?", "simple": "Is the evidence good enough for official guidelines to tell people to cut ultra-processed food specifically?"}, "claim_evaluated": {"research": "The evidence is strong enough to justify ultra-processed-specific dietary guidance (beyond existing nutrient-based advice).", "simple": "The evidence is solid enough for official dietary guidelines to single out 'ultra-processed food' and tell people to limit it."}, "depends_on": {"research": "This is an evidence-sufficiency judgement authorities directly split on: the 2025 US Dietary Guidelines Advisory Committee graded the evidence insufficient and made no UPF-specific recommendation, citing inconsistent definitions and gaps; the Nordic Nutrition Recommendations 2023 scoping review judged it strong enough to recommend limiting UPF; the 2025 Lancet Series argues for broad policy action. Same underlying literature, opposite verdicts \u2014 so the disagreement is partly about evidentiary standards and the definitional problem, not only about the data.", "simple": "The experts genuinely disagree using the SAME evidence: a US advisory panel said it wasn't good enough and made no recommendation; a Nordic review said it was; a Lancet series pushed for sweeping action. When experts split on the same data, the fight is partly about how high to set the bar \u2014 and about whether 'ultra-processed' is even defined well enough to legislate."}, "scored": true, "evidence_caveats": ["authorities split on the same literature \u2014 partly a dispute about evidentiary standards and the unresolved definition", "fast-moving: Re-run the FDA/USDA federal 'ultra-processed food' definition search before any republish \u2014 a federal definition was due in 2026 and would move this leaf."]}, {"id": "n_policy_labels", "parent_id": "n_policy", "evidence_quality": "thin", "label": "Do front-of-pack warning labels reduce purchases of the targeted products?", "children": [], "role": "leaf", "question": {"research": "Do front-of-pack warning labels reduce purchases of the targeted products?", "simple": "Do warning labels on the front of packages actually cut how much of those products people buy?"}, "claim_evaluated": {"research": "Front-of-pack warning labels reduce purchases of the targeted products.", "simple": "Putting warning labels on the front of unhealthy products makes people buy less of them."}, "depends_on": {"research": "Depends on the outcome (purchases, measured here, vs. consumption or health, not) and \u2014 critically \u2014 on the target: the strongest evidence (Chile's 2016 law) concerns NUTRIENT warning labels (high-in sugar/salt/saturated-fat/calories), not NOVA processing labels, and bundles labelling with marketing and school-sales restrictions. It is strong evidence that nutrient-targeted front-of-pack labels change purchasing; its transportability to a processing-specific label is an assumption, not a finding.", "simple": "The clear evidence (Chile) is that labels warning about SUGAR and SALT cut purchases \u2014 and they came packaged with ad and school rules. That's not the same as a label saying 'ultra-processed'. It shows warning labels can work; whether an 'ultra-processed' label specifically would is a leap."}, "scored": true, "evidence_caveats": ["strongest evidence targets NUTRIENTS (sugar/salt/fat), not processing \u2014 transportability to a UPF-specific label is an assumption", "no independent AGAINST located \u2014 one-sided"]}], "findings": [{"finding_id": "F-root-1", "node_id": "n_root", "direction": "COMPLICATES", "claim_paragraph": {"research": "There is no single measurement of 'are ultra-processed foods bad for you'. The literature separately measures whether the NOVA category can even be applied consistently, the size of the observational disease association, whether that association reflects processing or the nutrients it carries, whether controlled-feeding trials show processing itself causes overeating, and what policy changes. The strongest observational synthesis (an umbrella review of 45 pooled analyses covering ~9.9 million people) documents broad associations while explicitly stating that randomised trials are still needed and that residual confounding is the most pertinent limitation.", "simple": "No study measures 'is ultra-processed food bad' all at once. Researchers ask separate questions \u2014 does 'ultra-processed' even mean one clear thing, do heavy eaters get sicker, is it the processing or the sugar and salt, do experiments show processing itself causes overeating, and do labels work \u2014 and the answers differ. Being sure about one doesn't make you right about the others."}, "effect_size": {"research": "qualitative", "simple": "qualitative"}, "source_type": "systematic-review", "source_citation": "Lane et al. 2024, Ultra-processed food exposure and adverse health outcomes: umbrella review of epidemiological meta-analyses, BMJ 384:e077310.", "triggers_split_to": ["n_concept", "n_assoc", "n_cause", "n_policy"], "tension_with": [], "source_strength": "strong", "evidence_type": "review", "source_cluster": "lane-umbrella", "caveat": {"research": "Umbrella review of observational meta-analyses; the authors note it 'did not consider specific confounder or mediator adjustments'.", "simple": "A round-up of many observational studies \u2014 it can show links, not causes."}}, {"finding_id": "F-root-2", "node_id": "n_root", "direction": "COMPLICATES", "claim_paragraph": {"research": "Evidence quality is sharply uneven across the sub-questions. The observational association rests on millions of participants; the causal question rests on a handful of small, short feeding trials (a 2024 systematic review found only four qualifying RCTs, with no significant effect in 30 of 42 outcomes); and the classification underpinning all of it fails inter-rater reliability tests. Confidence earned on the best-measured sub-question does not transfer to the others.", "simple": "We know a lot about some parts and little about others. Millions of people have been surveyed about their diets, but only a few small experiments actually test whether processing causes harm \u2014 and the very definition of 'ultra-processed' is applied inconsistently. Don't let the well-studied part vouch for the rest."}, "effect_size": {"research": "qualitative", "simple": "qualitative"}, "source_type": "systematic-review", "source_citation": "Dominguez-Rodriguez et al. 2024, Ultra-processed foods consumption and health-related outcomes: a systematic review of randomized controlled trials, Frontiers in Nutrition 11:1421728.", "triggers_split_to": [], "tension_with": [], "source_strength": "moderate", "evidence_type": "review", "source_cluster": "rct-review", "caveat": {"research": "Systematic review of only four heterogeneous RCTs with 20-40% dropout in three of them.", "simple": "Based on just four small experiments, several with lots of dropouts."}}, {"finding_id": "F-concept-1", "node_id": "n_concept", "direction": "COMPLICATES", "claim_paragraph": {"research": "This dimension has two distinct failure modes that must not be conflated. A classification can be UNRELIABLE (different raters disagree on what is ultra-processed) or REDUNDANT (reliable but adding nothing over conventional nutrient profiling). They are separate questions with separate evidence, and a category could fail either test while passing the other.", "simple": "Two different ways the label could be weak: experts might not agree on what counts as 'ultra-processed' (unreliable), or they might agree but the label tells you nothing that sugar-and-salt already doesn't (redundant). These are separate problems."}, "effect_size": {"research": "qualitative", "simple": "qualitative"}, "source_type": "single-study", "source_citation": "Braesco et al. 2022, Ultra-processed foods: how functional is the NOVA system?, European Journal of Clinical Nutrition 76:1245-1253.", "triggers_split_to": ["n_concept_reliable", "n_concept_beyond"], "tension_with": [], "source_strength": "moderate", "evidence_type": "theoretical", "source_cluster": "nova-reliability", "caveat": {"research": "A framing of the two failure modes, not a measurement.", "simple": "A point about how the category could fail, not a new study."}}, {"finding_id": "F-rel-1", "node_id": "n_concept_reliable", "direction": "CHALLENGES", "claim_paragraph": {"research": "When 159 and 177 food-and-nutrition specialists independently assigned foods to NOVA groups, inter-rater agreement was poor: Fleiss' kappa was 0.32 for 120 marketed products (with ingredient lists) and 0.34 for 111 generic items (without). Agreement stayed low even when full ingredient information was available, so it is not a fixable data-access problem. The authors conclude 'current NOVA criteria do not allow for robust and functional food assignments.'", "simple": "When ~160-180 nutrition experts each sorted the same foods, they often disagreed on what was 'ultra-processed' \u2014 agreement was poor (a kappa of about 0.3, where 1 is perfect). It stayed poor even when they could see the full ingredient list. The researchers concluded the current rules don't let people classify foods consistently."}, "effect_size": {"research": "Fleiss' kappa 0.32 (marketed) / 0.34 (generic) \u2014 poor agreement", "simple": "experts agreed only about a third as well as perfect agreement"}, "source_type": "single-study", "source_citation": "Braesco et al. 2022, Ultra-processed foods: how functional is the NOVA system?, European Journal of Clinical Nutrition 76:1245-1253.", "triggers_split_to": [], "tension_with": ["F-gui-2", "F-lab-1", "F-mag-1"], "source_strength": "moderate", "evidence_type": "observational", "source_cluster": "nova-reliability", "caveat": {"research": "One reliability study, French specialists, online survey; a subset of foods (e.g. a 90-item cluster assigned 91% to NOVA-4) did classify consistently \u2014 the disagreement concentrates in ambiguous foods.", "simple": "One study of French experts; some clearly-processed foods were easy to agree on \u2014 the disagreement is about the borderline cases."}}, {"finding_id": "F-rel-2", "node_id": "n_concept_reliable", "direction": "COMPLICATES", "claim_paragraph": {"research": "Defenders of the concept argue that NOVA has validity and utility for science and policy and that the ultra-processed category tracks something real that nutrient profiling misses. But these defences are made on grounds of utility and construct validity, not measured reliability: no located source rebuts the inter-rater figures with a competing reliability estimate. So they complicate the picture (the category may be useful despite poor agreement) without providing evidence that classifiers actually agree \u2014 the FOR direction of this leaf carries no independent evidence.", "simple": "Supporters argue the 'ultra-processed' idea is useful and captures something real a nutrient label misses. That may be true \u2014 but it's an argument about usefulness, not about whether experts agree on what counts. Nobody has shown they DO agree, so there's really no evidence on the 'yes, it's consistent' side."}, "effect_size": {"research": "qualitative; utility argued, measured reliability not rebutted", "simple": "argues usefulness, not that experts agree"}, "source_type": "single-study", "source_citation": "e.g. Monteiro et al., The validity and utility of Nova and the concept of ultra-processed foods for science and policy, Nature Food (2026); AJCN 2023 debate 'YES' position.", "triggers_split_to": [], "tension_with": [], "source_strength": "thin", "evidence_type": "theoretical", "source_cluster": "nova-defence", "caveat": {"research": "Position/utility argument from the concept's proponents; not a measured reliability rebuttal \u2014 the FOR side of this leaf carries no independent evidence, so the leaf is effectively one-sided.", "simple": "An argument from the idea's supporters, not evidence that classification is consistent."}}, {"finding_id": "F-bey-1", "node_id": "n_concept_beyond", "direction": "SUPPORTS", "claim_paragraph": {"research": "A review of 37 prospective-cohort studies (91 models, 87 outcomes) found that 64 of 66 significant ultra-processed-food\u2013outcome associations remained significant after adjustment for diet quality or dietary pattern, and 136 of 142 individual adjustments did not explain the association (all-cause mortality 15/15 unchanged; CVD 29/31; cancer 8/8). The authors conclude 'the adverse consequences of UPFs are independent of dietary quality or pattern.'", "simple": "In a review of 37 long-term studies, the link between ultra-processed food and disease stayed almost every time even after accounting for how healthy the diet was overall (64 of 66 links held). The authors concluded the harm seems to be about the processing itself, not just the nutrients."}, "effect_size": {"research": "64/66 associations survive diet-quality adjustment", "simple": "the link held in 64 of 66 cases after accounting for diet quality"}, "source_type": "systematic-review", "source_citation": "Dicken & Batterham 2022, The Role of Diet Quality in Mediating the Association between Ultra-Processed Food Intake, Obesity and Health-Related Outcomes: A Review of Prospective Cohort Studies, Nutrients 14(1):23.", "triggers_split_to": [], "tension_with": ["F-bey-2", "F-bey-3", "F-con-2"], "source_strength": "moderate", "evidence_type": "review", "source_cluster": "dietquality-review", "caveat": {"research": "Reviews observational studies whose exposure and confounders are both from self-reported diet; 'unchanged after adjustment' can also reflect over- or under-adjustment, and residual confounding remains.", "simple": "Built from studies where people report their own diets; 'the link held' isn't the same as proof it's the processing."}}, {"finding_id": "F-bey-2", "node_id": "n_concept_beyond", "direction": "CHALLENGES", "claim_paragraph": {"research": "A 2024 systematic review of UPF randomized trials concludes that 'the added value of classifying foods based on their industrial processing compared to traditional nutrient-based systems remains an unresolved controversy' \u2014 the experimental evidence does not establish that the processing dimension adds information beyond nutrients. Combined with the poor reliability of the classification, the case that the category itself carries independent predictive value is weak on trial evidence.", "simple": "A 2024 review of the actual experiments says whether the 'ultra-processed' label adds anything beyond checking nutrients is still an open, unsettled question. The experiments don't show the label carries extra information on its own."}, "effect_size": {"research": "qualitative; added value 'unresolved'", "simple": "unresolved \u2014 no clear extra value shown"}, "source_type": "systematic-review", "source_citation": "Dominguez-Rodriguez et al. 2024, Frontiers in Nutrition 11:1421728.", "triggers_split_to": [], "tension_with": ["F-bey-1"], "source_strength": "moderate", "evidence_type": "review", "source_cluster": "rct-review", "caveat": {"research": "Only four RCTs; absence of demonstrated added value is not proof of no added value.", "simple": "Based on only four experiments \u2014 'not shown' isn't 'disproven'."}}, {"finding_id": "F-bey-3", "node_id": "n_concept_beyond", "direction": "CHALLENGES", "claim_paragraph": {"research": "The large 2024 US cohort found its ultra-processed-food\u2013mortality association became 'less pronounced after overall dietary quality was taken into account, suggesting that dietary quality has a stronger influence on long term health than ultra-processed food consumption' \u2014 evidence that, in at least this dataset, much of the signal tracks nutrients the category is supposed to add value beyond. The added-value question and the confounding question are the same statistic read from two sides.", "simple": "The biggest recent US study found the ultra-processed link got weaker once overall diet quality was accounted for \u2014 hinting that a lot of the harm is really about the nutrients, which is exactly what the label is supposed to add value beyond. Whether the label adds anything and whether the link is confounded are the same question."}, "effect_size": {"research": "qualitative", "simple": "qualitative"}, "source_type": "single-study", "source_citation": "Fang et al. 2024, Association of ultra-processed food consumption with all cause and cause specific mortality, BMJ 385:e078476.", "triggers_split_to": [], "tension_with": ["F-bey-1"], "source_strength": "moderate", "evidence_type": "observational", "source_cluster": "bmj-cohort", "caveat": {"research": "'Less pronounced' is not 'eliminated'; adjusting for diet quality may over-control if nutrients lie on the causal pathway of processing.", "simple": "The link shrank but didn't vanish \u2014 and adjusting this way can hide real effects too."}}, {"finding_id": "F-assoc-1", "node_id": "n_assoc", "direction": "COMPLICATES", "claim_paragraph": {"research": "Three distinct questions govern this dimension: whether an association exists and how large, whether it survives adjustment for nutrients and confounders, and whether it is uniform or concentrated in subgroups. Almost all of the evidence is observational and rests on self-reported diet (food-frequency questionnaires), so residual confounding and healthy-user bias are live throughout \u2014 the same measurement error affects both the exposure and the attempts to adjust it away.", "simple": "Three separate questions here: is there a link and how big, does it hold up when you account for a generally poor diet, and is every ultra-processed food equally to blame. Nearly all of it comes from people reporting their own eating, which is error-prone \u2014 so you can never fully rule out other explanations."}, "effect_size": {"research": "qualitative", "simple": "qualitative"}, "source_type": "systematic-review", "source_citation": "Lane et al. 2024, BMJ 384:e077310 (residual-confounding discussion).", "triggers_split_to": ["n_assoc_magnitude", "n_assoc_confound", "n_assoc_subgroup"], "tension_with": [], "source_strength": "moderate", "evidence_type": "theoretical", "source_cluster": "lane-umbrella", "caveat": {"research": "A methodological framing of the dimension, not a measurement.", "simple": "A point about how these studies work, not a new measurement."}}, {"finding_id": "F-mag-1", "node_id": "n_assoc_magnitude", "direction": "SUPPORTS", "claim_paragraph": {"research": "An umbrella review of 45 pooled analyses (~9.9 million people) graded several associations as 'convincing' or 'highly suggestive': cardiovascular-disease mortality (RR 1.50, 95% CI 1.37-1.63), type-2 diabetes (dose-response RR 1.12, 1.11-1.13), common mental disorders (OR 1.53, 1.43-1.63), all-cause mortality (RR 1.21, 1.15-1.27), and obesity (OR 1.55, 1.36-1.77). The breadth and consistency of higher-tier associations is not trivially small.", "simple": "Pooling studies of nearly 10 million people, the strongest-graded links are real and sizeable: about 50% higher heart-disease death, ~20% higher overall death, and ~55% higher obesity odds for the heaviest ultra-processed eaters. Across many diseases, the link is not tiny."}, "effect_size": {"research": "CVD-mortality RR 1.50; all-cause mortality RR 1.21; obesity OR 1.55", "simple": "~20-55% higher risk across major outcomes"}, "source_type": "systematic-review", "source_citation": "Lane et al. 2024, Ultra-processed food exposure and adverse health outcomes: umbrella review of epidemiological meta-analyses, BMJ 384:e077310.", "triggers_split_to": [], "tension_with": ["F-cau-1", "F-rel-1", "F-sub-1"], "source_strength": "strong", "evidence_type": "review", "source_cluster": "lane-umbrella", "caveat": {"research": "Observational inputs; graded evidence-tiers reflect statistical strength/consistency, not causation; residual confounding flagged by the authors as most pertinent.", "simple": "These are links, not proof of cause \u2014 the pooled studies just compare eaters, they don't run experiments."}}, {"finding_id": "F-mag-2", "node_id": "n_assoc_magnitude", "direction": "SUPPORTS", "claim_paragraph": {"research": "An independent scoping review for the Nordic Nutrition Recommendations 2023 (12 systematic reviews including 5 meta-analyses, plus 44 studies) concluded the evidence linking ultra-processed food to weight gain, cardiovascular disease, type-2 diabetes, and all-cause mortality is 'strong enough to support dietary recommendations to limit' its consumption \u2014 a second synthesis team reaching a concordant magnitude verdict.", "simple": "A separate Nordic government review of dozens of studies also concluded the link to weight gain, heart disease, diabetes, and early death is strong enough to tell people to cut back. Two independent expert teams, same read on the size of the link."}, "effect_size": {"research": "qualitative; concordant across four major outcomes", "simple": "strong enough to recommend limiting"}, "source_type": "systematic-review", "source_citation": "Juul & Bere 2024, Ultra-processed foods - a scoping review for Nordic Nutrition Recommendations 2023, Food & Nutrition Research 68.", "triggers_split_to": [], "tension_with": [], "source_strength": "strong", "evidence_type": "review", "source_cluster": "nordic-scoping", "caveat": {"research": "Synthesizes overlapping observational cohorts with the umbrella review (partial non-independence on the underlying primary studies); still correlational at base.", "simple": "Draws on many of the same underlying studies as the other review, and those are still correlational."}}, {"finding_id": "F-mag-3", "node_id": "n_assoc_magnitude", "direction": "CHALLENGES", "claim_paragraph": {"research": "In one of the most rigorously controlled cohorts (74,563 women + 39,501 men, 48,193 deaths over 30+ years), the highest-versus-lowest quartile of total ultra-processed intake carried only a 4% higher all-cause mortality (1536 vs 1472 deaths per 100,000 person-years), with no association for cardiovascular, cancer, or respiratory mortality. The pooled higher-tier relative risks and this modest, well-adjusted cohort estimate are both 'the magnitude' \u2014 which one to weigh is a judgement about design.", "simple": "In one of the best-run studies, the heaviest ultra-processed eaters had just 4% higher overall death risk \u2014 and no higher risk of dying from heart disease, cancer, or lung disease. So 'how big is the link' depends on which study you trust: the big pooled numbers, or this smaller, more carefully adjusted one."}, "effect_size": {"research": "+4% all-cause mortality (top vs bottom quartile); null for CVD/cancer/respiratory", "simple": "only ~4% higher overall death risk in a well-controlled study"}, "source_type": "single-study", "source_citation": "Fang et al. 2024, Association of ultra-processed food consumption with all cause and cause specific mortality, BMJ 385:e078476.", "triggers_split_to": [], "tension_with": [], "source_strength": "moderate", "evidence_type": "observational", "source_cluster": "bmj-cohort", "caveat": {"research": "Highly educated health-professional cohort (limits generalisability but also confounding); self-reported diet; a small relative risk over a large population can still be many deaths.", "simple": "Nurses and health workers, so healthier than average; a small percentage across millions of people is still a lot of deaths."}}, {"finding_id": "F-con-1", "node_id": "n_assoc_confound", "direction": "SUPPORTS", "claim_paragraph": {"research": "The review of 37 prospective cohorts found 64 of 66 significant ultra-processed-food associations survived adjustment for diet quality, and 136 of 142 adjustments did not explain the association \u2014 including all-cause mortality (15/15 unchanged), CVD (29/31), cancer (8/8), and type-2 diabetes (7/7). On this evidence the association is not merely a proxy for poor nutrient quality; something about processing appears to contribute independently.", "simple": "Across 37 long-term studies, the ultra-processed link almost always stayed after accounting for how healthy the diet was overall \u2014 for death, heart disease, cancer, and diabetes alike. That points to the processing itself mattering, not just the sugar and salt."}, "effect_size": {"research": "136/142 diet-quality adjustments left the association intact", "simple": "adjusting for diet quality removed the link only 6 times out of 142"}, "source_type": "systematic-review", "source_citation": "Dicken & Batterham 2022, Nutrients 14(1):23.", "triggers_split_to": [], "tension_with": ["F-con-2"], "source_strength": "moderate", "evidence_type": "review", "source_cluster": "dietquality-review", "caveat": {"research": "Observational throughout; 'survives adjustment' cannot distinguish a true processing effect from unmeasured confounding correlated with UPF intake.", "simple": "Still all correlational \u2014 the link surviving doesn't prove processing is the cause; something unmeasured could travel with it."}}, {"finding_id": "F-con-2", "node_id": "n_assoc_confound", "direction": "CHALLENGES", "claim_paragraph": {"research": "The large 2024 US cohort reached the opposite conclusion for mortality: the ultra-processed-food association 'was less pronounced after overall dietary quality was taken into account, suggesting that dietary quality has a stronger influence on long term health than ultra-processed food consumption.' Where this well-powered study adjusted carefully, nutrient quality \u2014 not processing per se \u2014 carried most of the signal.", "simple": "The big 2024 US study found the opposite: once it accounted for overall diet quality, the ultra-processed link faded a lot. It concluded that how nutritious the diet is matters more than whether the food is processed."}, "effect_size": {"research": "association attenuates after diet-quality adjustment", "simple": "the link shrank once diet quality was accounted for"}, "source_type": "single-study", "source_citation": "Fang et al. 2024, BMJ 385:e078476.", "triggers_split_to": [], "tension_with": ["F-bey-1", "F-con-1"], "source_strength": "moderate", "evidence_type": "observational", "source_cluster": "bmj-cohort", "caveat": {"research": "A single cohort; adjusting for diet quality could over-control if the nutrient profile is part of how processing acts. 'Less pronounced' is not 'zero'.", "simple": "One study \u2014 and this kind of adjustment can also hide a real effect if the nutrients are how processing does its harm."}}, {"finding_id": "F-con-3", "node_id": "n_assoc_confound", "direction": "COMPLICATES", "claim_paragraph": {"research": "Both directions inherit an unfixable limitation: exposure, confounders, and diet-quality indices are all derived from the same self-reported dietary instruments, so neither 'survives adjustment' nor 'attenuates' can settle causation. The umbrella review's authors name residual confounding as 'perhaps most pertinent', and only controlled-feeding trials can break the deadlock \u2014 which is why this leaf's answer partly waits on the causal dimension.", "simple": "Both sides share the same weakness: everything comes from people reporting their own diets, so no amount of statistical adjustment can prove cause. Only real experiments can settle it \u2014 which is a different question, handled elsewhere in this map."}, "effect_size": {"research": "qualitative", "simple": "qualitative"}, "source_type": "systematic-review", "source_citation": "Lane et al. 2024, BMJ 384:e077310 (residual-confounding limitation).", "triggers_split_to": [], "tension_with": [], "source_strength": "moderate", "evidence_type": "theoretical", "source_cluster": "lane-umbrella", "caveat": {"research": "A framing of the shared limitation, not a measurement.", "simple": "A point about why surveys can't settle this, not a new study."}}, {"finding_id": "F-sub-1", "node_id": "n_assoc_subgroup", "direction": "SUPPORTS", "claim_paragraph": {"research": "In the 2024 US cohort, the total-ultra-processed association was driven by specific subgroups rather than spread evenly: meat/poultry/seafood-based ready-to-eat products showed the strongest and most consistent association with mortality, followed by sugar- and artificially-sweetened beverages, dairy-based desserts, and ultra-processed breakfast foods, while several other subgroups (fats/condiments/sauces, packaged sweet and savory snacks, ready-to-eat dishes) showed no significant association. The category is not internally uniform.", "simple": "In the big US study, the link to earlier death was strongest for particular foods \u2014 processed meats most of all, then sugary drinks, dairy desserts, and processed breakfast foods \u2014 while several other ultra-processed foods showed no clear link. Not all ultra-processed foods behaved the same."}, "effect_size": {"research": "processed meat strongest; several UPF subgroups null", "simple": "processed meat most strongly linked; several others showed no link"}, "source_type": "single-study", "source_citation": "Fang et al. 2024, BMJ 385:e078476 (subgroup analyses).", "triggers_split_to": [], "tension_with": ["F-mag-1"], "source_strength": "moderate", "evidence_type": "observational", "source_cluster": "bmj-cohort", "caveat": {"research": "'No significant association' for a subgroup is not evidence it is safe; subgroup analyses have less power and this concentration pattern comes from a single cohort.", "simple": "'No clear link' isn't the same as 'proven harmless', and this split comes from just one study."}}, {"finding_id": "F-sub-2", "node_id": "n_assoc_subgroup", "direction": "COMPLICATES", "claim_paragraph": {"research": "The umbrella review's broad, higher-tier associations are stated for TOTAL ultra-processed exposure across many outcomes and cannot, on their own, distinguish a genuinely concentrated harm (a few bad subgroups) from a diffuse one. A total-UPF exposure measure that mixes harmful, neutral, and possibly protective subgroups will understate the worst categories and overstate the benign ones \u2014 so a single 'ultra-processed' policy target may be aiming at a heterogeneous mixture.", "simple": "The big pooled numbers are for ALL ultra-processed food lumped together, so they can't tell you whether a few foods do the damage or all of them share it. Lumping harmful, neutral, and maybe-helpful foods into one number hides that \u2014 and a policy targeting 'ultra-processed food' as a whole hits the harmless ones too."}, "effect_size": {"research": "qualitative", "simple": "qualitative"}, "source_type": "systematic-review", "source_citation": "Lane et al. 2024, BMJ 384:e077310 (total-UPF exposure).", "triggers_split_to": [], "tension_with": [], "source_strength": "moderate", "evidence_type": "review", "source_cluster": "lane-umbrella", "caveat": {"research": "Pooled total-exposure associations neither confirm nor refute concentration; an independent cohort with a full subgroup breakdown was not located under the protocol.", "simple": "The pooled figures don't settle the subgroup question either way; we couldn't find a second study breaking it down."}}, {"finding_id": "F-cause-1", "node_id": "n_cause", "direction": "COMPLICATES", "claim_paragraph": {"research": "Controlled-feeding trials can hold nutrient composition roughly constant and vary only processing, isolating a processing effect that observational designs cannot \u2014 but they are few, small, and short, run in metabolic-ward or motivated-volunteer settings, and their mechanism is contested. A real intake effect does not by itself locate the causal lever on 'processing' as opposed to energy density, texture, or eating rate, which nutrient- or design-based policy could also target.", "simple": "Experiments that feed people matched diets and change only the processing can show cause in a way surveys can't. But there are only a few, they're small and short, and even when they find an effect, researchers argue about WHY \u2014 the processing, or just that these foods are soft, calorie-dense, and quick to eat?"}, "effect_size": {"research": "qualitative", "simple": "qualitative"}, "source_type": "single-study", "source_citation": "Hall et al. 2019, Cell Metabolism 30(1):67-77 (mechanism discussion).", "triggers_split_to": ["n_cause_intake"], "tension_with": [], "source_strength": "moderate", "evidence_type": "theoretical", "source_cluster": "hall-rct", "caveat": {"research": "A framing of what feeding trials can and cannot isolate, not a standalone measurement.", "simple": "A point about what these experiments can and can't tell us."}}, {"finding_id": "F-cau-1", "node_id": "n_cause_intake", "direction": "SUPPORTS", "claim_paragraph": {"research": "In a randomized crossover inpatient trial (n = 20, two weeks per arm), diets matched for presented calories, energy density, macronutrients, sugar, sodium, and fibre still produced about 500 kcal/day more ad libitum intake on the ultra-processed diet, with a 0.9 kg weight gain versus an equivalent loss on the unprocessed diet. Because participants could not choose different foods and the nutrients were matched, this is the strongest evidence that processing itself drives overeating.", "simple": "In a locked-in research-ward experiment, people were offered ultra-processed or unprocessed meals matched for calories, sugar, fat, salt, and fibre. On the ultra-processed diet they ate ~500 extra calories a day and gained about 2 lb; on the unprocessed diet they lost about the same. With the nutrients matched, the processing itself seems to drive overeating."}, "effect_size": {"research": "+~500 kcal/day; +0.9 kg on UP vs equivalent loss on unprocessed", "simple": "~500 extra calories/day and ~2 lb gained on the processed diet"}, "source_type": "single-study", "source_citation": "Hall et al. 2019, Ultra-Processed Diets Cause Excess Calorie Intake and Weight Gain: An Inpatient Randomized Controlled Trial of Ad Libitum Food Intake, Cell Metabolism 30(1):67-77.", "triggers_split_to": [], "tension_with": ["F-cau-3", "F-mag-1"], "source_strength": "moderate", "evidence_type": "experimental", "source_cluster": "hall-rct", "caveat": {"research": "n = 20, two weeks, metabolic ward \u2014 generalisability limited; the authors note slight protein differences could explain up to half the intake gap, and faster eating rate is implicated, so 'processing' may act via energy density/texture rather than processing as such.", "simple": "Only 20 people for two weeks in a research ward; the authors say a small protein difference and faster eating could explain much of it \u2014 so it may be about the food being soft and dense, not 'processing' itself."}}, {"finding_id": "F-cau-2", "node_id": "n_cause_intake", "direction": "SUPPORTS", "claim_paragraph": {"research": "The longest UPF feeding trial to date (randomized crossover, 55 adults, 8-week arms, both diets following UK healthy-eating guidance) found roughly twice the weight loss on the minimally-processed diet (-2.06%) versus the ultra-processed diet (-1.05%) \u2014 an independent second trial pointing the same way, and notably even when both diets were nutritionally 'healthy'.", "simple": "The longest experiment so far \u2014 55 adults, eight weeks each on ultra-processed versus minimally-processed versions of a HEALTHY diet \u2014 found about twice the weight loss on the minimally-processed one. A second, independent experiment pointing the same way, even with both diets designed to be nutritious."}, "effect_size": {"research": "-2.06% (MPF) vs -1.05% (UPF) body weight at 8 weeks", "simple": "about twice the weight loss on the less-processed diet"}, "source_type": "single-study", "source_citation": "Dicken et al. 2025, Ultra-processed or minimally processed diets following healthy dietary guidelines on weight and cardiometabolic health: a randomized, crossover trial, Nature Medicine.", "triggers_split_to": [], "tension_with": ["F-cau-3"], "source_strength": "moderate", "evidence_type": "experimental", "source_cluster": "dicken-rct", "caveat": {"research": "Small (n=55); the between-diet gap is ~1 percentage point of body weight over 8 weeks; cardiometabolic markers did NOT differ between diets (both improved from baseline); Nature Medicine published formal critiques (Ludwig et al.; Robinson & Forde; Wang & Peng) and the authors' reply \u2014 carry the dispute.", "simple": "Small study; the actual difference was about 1% of body weight; blood-pressure and cholesterol markers were the same on both diets; and other scientists formally challenged the conclusions."}}, {"finding_id": "F-cau-3", "node_id": "n_cause_intake", "direction": "CHALLENGES", "claim_paragraph": {"research": "A 2024 systematic review of ultra-processed-food RCTs found only four qualifying trials and no significant effect in 30 of 42 outcomes, concluding that 'the available evidence to date cannot establish a clear causal link between the degree of food processing and adverse health outcomes.' The controlled-trial base is too small and heterogeneous to certify a general causal claim beyond the specific intake finding.", "simple": "A 2024 review of the actual experiments found only four, with no significant effect in 30 of 42 things they measured. It concluded the evidence 'cannot establish a clear causal link' between how processed food is and harm. The experiments are too few to prove a broad claim."}, "effect_size": {"research": "30/42 outcomes null across 4 RCTs; 'cannot establish a clear causal link'", "simple": "no significant effect in 30 of 42 outcomes"}, "source_type": "systematic-review", "source_citation": "Dominguez-Rodriguez et al. 2024, Ultra-processed foods consumption and health-related outcomes: a systematic review of randomized controlled trials, Frontiers in Nutrition 11:1421728.", "triggers_split_to": [], "tension_with": ["F-cau-1", "F-cau-2"], "source_strength": "moderate", "evidence_type": "review", "source_cluster": "rct-review", "caveat": {"research": "Many of the 42 outcomes are secondary clinical markers, not intake/weight; a null across underpowered trials is weak evidence of no effect, and this review includes the Hall ward study among its four.", "simple": "Most of those 42 measures were secondary health markers, not calories or weight \u2014 and 'no effect found' in tiny studies isn't proof there's none."}}, {"finding_id": "F-policy-1", "node_id": "n_policy", "direction": "COMPLICATES", "claim_paragraph": {"research": "Two different policy questions live here. One is a judgement about evidence sufficiency \u2014 should authorities issue ultra-processed-specific guidance \u2014 on which official bodies openly split. The other is whether a given instrument measurably changes behaviour. Crucially, the strongest instrument evidence concerns NUTRIENT-based front-of-pack labels, not processing-based ones, so it speaks directly to nutrient policy and only by assumption to ultra-processed-specific policy.", "simple": "Two separate policy questions: do the official panels think the evidence is good enough to single out 'ultra-processed food' (they disagree), and do labels actually change what people buy (yes \u2014 but those labels flag sugar and salt, not 'ultra-processed', which is a different target)."}, "effect_size": {"research": "qualitative", "simple": "qualitative"}, "source_type": "single-study", "source_citation": "Taillie et al. 2020, PLOS Medicine 17(2):e1003015; 2025 US DGAC scientific report (policy contrast).", "triggers_split_to": ["n_policy_guidance", "n_policy_labels"], "tension_with": [], "source_strength": "moderate", "evidence_type": "theoretical", "source_cluster": "chile-labels", "caveat": {"research": "A framing of the two policy questions, not a measurement.", "simple": "A point about two different policy questions, not a new study."}}, {"finding_id": "F-gui-1", "node_id": "n_policy_guidance", "direction": "CHALLENGES", "claim_paragraph": {"research": "The 2025 US Dietary Guidelines Advisory Committee conducted a systematic review of ultra-processed food and obesity/body composition and graded the evidence insufficient to draw a conclusion, making no ultra-processed-specific recommendation \u2014 citing inconsistent definitions and evidence gaps. The strongest US institutional synthesis declined to issue the guidance the claim asserts is warranted.", "simple": "The main US expert panel for the 2025-2030 dietary guidelines reviewed the evidence and decided it wasn't strong enough to make any specific recommendation about ultra-processed food \u2014 partly because 'ultra-processed' isn't defined consistently. The top US body chose not to issue the guidance."}, "effect_size": {"research": "qualitative; evidence graded insufficient, no recommendation", "simple": "the US panel found the evidence not strong enough"}, "source_type": "systematic-review", "source_citation": "2025 Dietary Guidelines Advisory Committee, Scientific Report (Dietary Patterns with Ultra-Processed Foods and Growth, Body Composition, and Risk of Obesity systematic review, 2024).", "triggers_split_to": [], "tension_with": ["F-gui-2"], "source_strength": "strong", "evidence_type": "review", "source_cluster": "dgac-2025", "caveat": {"research": "'Insufficient to conclude' reflects a deliberately high bar and the definitional problem; it is not a finding that UPF is harmless.", "simple": "'Not enough evidence to say' isn't the same as 'proven safe' \u2014 the bar is set high."}}, {"finding_id": "F-gui-2", "node_id": "n_policy_guidance", "direction": "SUPPORTS", "claim_paragraph": {"research": "Reviewing much the same literature, the Nordic Nutrition Recommendations 2023 scoping review concluded the evidence IS strong enough to support dietary recommendations to limit ultra-processed food, and the 2025 Lancet UPF Series (43 authors) argues the evidence base justifies broad policy action including labelling and marketing restriction. Two authoritative bodies reached the opposite evidence-sufficiency verdict from the US committee.", "simple": "Looking at largely the same studies, a Nordic government review said the evidence IS good enough to tell people to cut ultra-processed food, and a 2025 Lancet series pushed for sweeping policy. Same evidence, opposite verdict from the US panel."}, "effect_size": {"research": "qualitative; 'strong enough to recommend limiting'", "simple": "Nordic review and Lancet series say the evidence suffices"}, "source_type": "systematic-review", "source_citation": "Juul & Bere 2024, Food & Nutrition Research 68 (NNR 2023 scoping review); Monteiro et al. 2025, Lancet UPF Series.", "triggers_split_to": [], "tension_with": ["F-gui-1", "F-rel-1"], "source_strength": "moderate", "evidence_type": "review", "source_cluster": "nordic-scoping", "caveat": {"research": "The Lancet Series is led by the NOVA concept's originators/advocates \u2014 labelled position evidence under the protocol, not sole support; the Nordic review carries the independent institutional weight here.", "simple": "The Lancet series is written by the idea's leading champions, so it's a stated position \u2014 the Nordic review is the more neutral support."}}, {"finding_id": "F-gui-3", "node_id": "n_policy_guidance", "direction": "COMPLICATES", "claim_paragraph": {"research": "The bodies are reading similar data to opposite verdicts, so the disagreement is not only empirical: it turns partly on how high to set the evidentiary bar and on the unresolved definition of 'ultra-processed'. A guidance target that cannot be classified consistently (see the reliability leaf) is hard to legislate regardless of the association's strength \u2014 the guidance question inherits the concept question.", "simple": "Because the experts split on the same evidence, the fight is partly about how much proof you demand \u2014 and about the fact that 'ultra-processed' isn't defined consistently. It's hard to write a rule around a category experts can't reliably apply, no matter how real the harm is."}, "effect_size": {"research": "qualitative", "simple": "qualitative"}, "source_type": "single-study", "source_citation": "Braesco et al. 2022, European Journal of Clinical Nutrition 76:1245-1253 (definitional dependence).", "triggers_split_to": [], "tension_with": [], "source_strength": "moderate", "evidence_type": "theoretical", "source_cluster": "nova-reliability", "caveat": {"research": "An interpretation of why the bodies disagree, linking to the reliability leaf; not a new measurement.", "simple": "A point about why the experts disagree, connected to the definition problem."}}, {"finding_id": "F-lab-1", "node_id": "n_policy_labels", "direction": "SUPPORTS", "claim_paragraph": {"research": "Chile's 2016 Law of Food Labeling \u2014 mandatory front-of-pack 'high in' warning labels \u2014 was followed by a 23.7% fall in purchases of high-in sugar-sweetened beverages versus the pre-regulation-trend counterfactual, tracked across 2,383 households and ~70,000 household-months. This is strong policy-natural-experiment evidence that front-of-pack warning labels change what people buy.", "simple": "After Chile put mandatory warning labels on the front of unhealthy products in 2016, purchases of labelled sugary drinks fell by about 24% compared with the trend beforehand, measured across ~2,400 households. Strong real-world evidence that front-of-pack warnings change buying."}, "effect_size": {"research": "-23.7% high-in sugar-sweetened-beverage purchases vs counterfactual", "simple": "about 24% fewer sugary-drink purchases"}, "source_type": "single-study", "source_citation": "Taillie et al. 2020, An evaluation of Chile's Law of Food Labeling and Advertising on sugar-sweetened beverage purchases from 2015 to 2017, PLOS Medicine 17(2):e1003015.", "triggers_split_to": [], "tension_with": ["F-rel-1"], "source_strength": "moderate", "evidence_type": "quasi-experimental", "source_cluster": "chile-labels", "caveat": {"research": "The labels flagged NUTRIENTS (added sugar/sodium/saturated-fat thresholds), NOT the ultra-processed category, and came bundled with marketing and school-sales restrictions; outcome is purchases, not consumption or health.", "simple": "Those labels warned about sugar and salt, not 'ultra-processed' \u2014 and came with ad and school rules too. It measured what people bought, not what they ate or their health."}}, {"finding_id": "F-lab-2", "node_id": "n_policy_labels", "direction": "COMPLICATES", "claim_paragraph": {"research": "The label evidence's transportability to ultra-processed-specific policy is an assumption, not a finding. Chile targeted nutrients that are straightforward to measure and threshold; the ultra-processed category is defined by processing and, per the reliability leaf, cannot be applied consistently \u2014 so a warning label reading 'ultra-processed' would face a classification problem that a 'high in sugar' label does not. Evidence that nutrient labels work is not evidence that a processing label would.", "simple": "That labels work for sugar and salt doesn't prove an 'ultra-processed' label would. Sugar is easy to measure and put a number on; 'ultra-processed' is a fuzzy category experts can't apply consistently \u2014 so a label based on it faces a problem the sugar label never did."}, "effect_size": {"research": "qualitative", "simple": "qualitative"}, "source_type": "single-study", "source_citation": "Taillie et al. 2020, PLOS Medicine 17(2):e1003015 (nutrient-threshold basis); Braesco et al. 2022 (classification reliability).", "triggers_split_to": [], "tension_with": [], "source_strength": "thin", "evidence_type": "theoretical", "source_cluster": "chile-labels", "caveat": {"research": "An interpretation of the target mismatch; no study has yet evaluated a processing-based front-of-pack label, so the AGAINST direction here is genuinely thin.", "simple": "Nobody has yet tested an 'ultra-processed' label, so this is reasoning about the gap, not a study."}}], "tensions": [{"a": "F-con-1", "b": "F-con-2", "kind": "empirical-contradiction", "note": {"research": "A review of 37 cohorts finds UPF associations survive diet-quality adjustment almost every time; a large single cohort finds the mortality association substantially attenuates after the same adjustment. A genuine live dispute about whether processing acts independently of nutrients.", "simple": "One review says the link almost always holds after accounting for diet quality; one big study says it fades. They genuinely disagree about whether it's the processing or the nutrients."}}, {"a": "F-bey-1", "b": "F-con-2", "kind": "assumption-sensitivity", "note": {"research": "'Does the category add value beyond nutrients' and 'is this association confounded by nutrients' are the same statistic viewed from two sides \u2014 survival of adjustment supports added value; attenuation implies redundancy. Which reading you take is an assumption about what adjustment means.", "simple": "Whether the 'ultra-processed' label adds anything, and whether the link is really just nutrients, are the same test seen two ways. The same adjustment result can be read as 'the label adds something' or 'it was nutrients all along.'"}}, {"a": "F-bey-1", "b": "F-bey-2", "kind": "assumption-sensitivity", "note": {"research": "Observational cohorts (adjustment survives) suggest the processing dimension adds value; the trial review calls the added value 'unresolved'. The verdict depends on which evidence type you privilege \u2014 adjusted cohorts or the sparse RCTs.", "simple": "The long-term studies suggest the label adds something; the experiments say it's unresolved. Your answer depends on whether you trust the surveys or the (few) experiments more."}}, {"a": "F-sub-1", "b": "F-mag-1", "kind": "scope-aggregation", "note": {"research": "The umbrella review's broad total-UPF associations vs the single-cohort finding that harm concentrates in a few subgroups (processed meat, sugary drinks) while others are null \u2014 a total-exposure average and a subgroup breakdown answer different questions; the aggregate can hide the structure.", "simple": "The big pooled numbers treat all ultra-processed food as one thing; the subgroup study shows a few foods drive the harm and others don't. Lumping them together hides which is which."}}, {"a": "F-gui-1", "b": "F-gui-2", "kind": "empirical-contradiction", "note": {"research": "The US advisory committee graded the evidence insufficient and made no UPF-specific recommendation; Nordic and Lancet bodies reading similar data judged it strong enough to act. Same literature, opposite evidence-sufficiency verdicts.", "simple": "The US panel said the evidence wasn't good enough; Nordic and Lancet experts said it was. Same studies, opposite calls."}}, {"a": "F-lab-1", "b": "F-rel-1", "kind": "context-transportability", "note": {"research": "Chile's success is evidence that NUTRIENT-threshold labels change purchasing; the reliability leaf shows the ultra-processed category cannot be classified consistently. A processing-based label would face a classification problem a 'high in sugar' label does not, so the effect does not transport by assumption.", "simple": "Chile's labels worked \u2014 but they flagged sugar, which is easy to measure. An 'ultra-processed' label targets a fuzzy category experts can't agree on, so you can't assume it would work the same way."}}, {"a": "F-mag-1", "b": "F-cau-1", "kind": "assumption-sensitivity", "note": {"research": "A modest-to-moderate observational relative risk for total UPF and a ~500 kcal/day controlled-feeding intake effect are different estimands: the cohort measures long-run associations across free-living diets, the trial measures short-run intake under matched nutrients. Which one 'the effect of ultra-processing' means is an assumption.", "simple": "A survey link across years and a 500-calorie jump in a two-week experiment measure different things. Both can be true; which one counts as 'the effect' is a choice."}}, {"a": "F-cau-1", "b": "F-cau-3", "kind": "empirical-contradiction", "note": {"research": "The landmark inpatient trial finds a clear processing effect on intake; the systematic review of four RCTs finds no significant effect in most outcomes and 'cannot establish a clear causal link'. The single strongest trial and the pooled trial base point different ways.", "simple": "The best single experiment found a clear effect; the round-up of all four experiments found mostly nothing. The standout study and the whole set disagree."}}, {"a": "F-cau-2", "b": "F-cau-3", "kind": "empirical-contradiction", "note": {"research": "The 2025 outpatient crossover finds twice the weight loss on the minimally-processed diet; the RCT systematic review concludes the trial base cannot establish a clear causal link. A dispute about whether the small, short trials collectively demonstrate causation.", "simple": "The 2025 experiment found more weight loss off ultra-processed food; the review of all the experiments says they don't add up to proof. They disagree on whether the experiments settle it."}}, {"a": "F-rel-1", "b": "F-mag-1", "kind": "assumption-sensitivity", "note": {"research": "If trained raters agree on the ultra-processed category only at Fleiss' kappa \u2248 0.3, then the exposure in every pooled association is measured with substantial classification error \u2014 which makes what a pooled relative risk 'means' depend on an assumption that the category was applied consistently.", "simple": "If experts barely agree on what's ultra-processed, then studies counting 'ultra-processed' intake are measuring a blurry thing \u2014 so the pooled risk numbers rest on assuming the category was applied consistently."}}, {"a": "F-rel-1", "b": "F-gui-2", "kind": "cross-dimension", "note": {"research": "The reliability failure (a classification leaf) directly bears on the policy leaf: bodies calling for UPF-specific guidance are proposing to legislate a category that trained specialists cannot apply consistently. The concept problem and the policy proposal pull against each other across dimensions.", "simple": "One finding says experts can't agree what 'ultra-processed' means; another says we should make rules about it. You can't easily legislate a category people can't reliably identify."}}, {"a": "F-bey-1", "b": "F-bey-3", "kind": "empirical-contradiction", "note": {"research": "Within the added-value leaf: the cohort review finds UPF associations survive diet-quality adjustment (added value), while the large single cohort finds its association attenuates after the same adjustment (redundant with nutrients). The same statistical operation, opposite verdicts.", "simple": "One review says the ultra-processed link holds after accounting for nutrients (so the label adds something); one big study says it fades (so it was the nutrients). Same test, opposite answers."}}]};

const STR_RANK = { strong: 0, moderate: 1, thin: 2 };
const DIR_LABEL = { SUPPORTS: "FOR", CHALLENGES: "AGAINST", COMPLICATES: "COMPLICATES" };
const DIR_COLOR = { SUPPORTS: "#5c7a64", CHALLENGES: "#a85d52", COMPLICATES: "#9a8a55" };
const TEASER_KINDS = new Set(["cross-dimension", "empirical-contradiction"]);

function buildIndex(d) {
  const nodeById = {}; d.nodes.forEach(n => (nodeById[n.id] = n));
  const findingById = {}; d.findings.forEach(f => (findingById[f.finding_id] = f));
  const findingsByNode = {};
  d.findings.forEach(f => { (findingsByNode[f.node_id] ||= []).push(f); });
  const subtree = {};
  const collect = (id) => {
    if (subtree[id]) return subtree[id];
    const set = new Set((findingsByNode[id] || []).map(f => f.finding_id));
    (nodeById[id].children || []).forEach(c => collect(c).forEach(x => set.add(x)));
    return (subtree[id] = set);
  };
  d.nodes.forEach(n => collect(n.id));
  const tnAdj = {};
  d.tensions.forEach(t => {
    (tnAdj[t.a] ||= []).push({ partner: t.b, kind: t.kind, note: t.note });
    (tnAdj[t.b] ||= []).push({ partner: t.a, kind: t.kind, note: t.note });
  });
  return { nodeById, findingById, findingsByNode, subtree, tnAdj };
}

function orderFindings(list) {
  const rank = f => (STR_RANK[f.source_strength] ?? 1);
  const tag = list.map((f, i) => ({ f, i }));
  const by = (a, b) => rank(a.f) - rank(b.f) || a.i - b.i;
  const S = tag.filter(x => x.f.direction === "SUPPORTS").sort(by);
  const C = tag.filter(x => x.f.direction === "CHALLENGES").sort(by);
  const X = tag.filter(x => x.f.direction === "COMPLICATES").sort(by);
  const inter = []; let i = 0;
  while (i < S.length || i < C.length) { if (i < S.length) inter.push(S[i]); if (i < C.length) inter.push(C[i]); i++; }
  return [...inter, ...X].map(x => x.f);
}

const pick = (x, reg) => (x && typeof x === "object" && !Array.isArray(x) && ("research" in x))
  ? (x[reg] ?? x.research) : x;

const crumb = (n, reg) => n.role === "topic" ? "Start"
  : pick(n.question, reg).replace(/\?+$/, "").replace(/^(How|Does|What|Are|Do)\s+/i, "").trim().slice(0, 24);

export default function App() {
  const idx = useMemo(() => buildIndex(DATA), []);
  const { nodeById, findingById, findingsByNode, subtree, tnAdj } = idx;

  const [current, setCurrent] = useState("n_root");
  const [reg, setReg] = useState("research");
  const P = x => pick(x, reg);
  const [path, setPath] = useState(["n_root"]);
  const [phase, setPhase] = useState("reading");
  const [step, setStep] = useState(0);
  const [seen, setSeen] = useState({});
  const [conf, setConf] = useState({});
  const [, setChoices] = useState({});
  const [visited, setVisited] = useState({ n_root: true });
  const [teasers, setTeasers] = useState(null);
  const [pendingChild, setPendingChild] = useState(null);
  const [slider, setSlider] = useState(50);

  const node = nodeById[current];
  const ordered = useMemo(() => orderFindings(findingsByNode[current] || []), [current]);

  useEffect(() => {
    if (phase === "reading" && ordered[step]) {
      const fid = ordered[step].finding_id;
      setSeen(s => (s[fid] ? s : { ...s, [fid]: true }));
    }
  }, [current, phase, step, ordered]);

  function enter(nodeId, newPath) {
    const n = nodeById[nodeId];
    setCurrent(nodeId); setPath(newPath); setStep(0); setTeasers(null); setPendingChild(null);
    setVisited(v => (v[nodeId] ? v : { ...v, [nodeId]: true }));
    if (n.scored) {
      const c = conf[nodeId] || {};
      if (c.posterior != null) setPhase("stop");
      else if (c.prior != null) setPhase("reading");
      else { setPhase("prior"); setSlider(50); }
    } else {
      const comps = (findingsByNode[nodeId] || []).filter(f => f.direction === "COMPLICATES");
      setPhase(comps.every(f => seen[f.finding_id]) ? "depend" : "reading");
    }
  }

  function next() {
    if (step < ordered.length - 1) { setStep(step + 1); return; }
    if (node.scored) { setPhase("posterior"); setSlider(Math.round(((conf[current]?.prior) ?? 0.5) * 100)); }
    else setPhase("depend");
  }

  function chooseChild(childId) {
    setChoices(c => ({ ...c, [current]: childId }));
    const sibs = (node.children || []).filter(c => c !== childId);
    const seenIds = Object.keys(seen);
    const ts = [];
    sibs.forEach(sib => {
      const sf = subtree[sib] || new Set();
      seenIds.forEach(sid => (tnAdj[sid] || []).forEach(adj => {
        if (sf.has(adj.partner) && TEASER_KINDS.has(adj.kind))
          ts.push({ sibling: sib, label: nodeById[sib].question, note: adj.note, seenId: sid });
      }));
    });
    const uniq = [...new Map(ts.map(t => [t.sibling + t.note, t])).values()];
    if (uniq.length) { setTeasers(uniq); setPendingChild(childId); setPhase("teaser"); }
    else enter(childId, [...path, childId]);
  }

  const firedFor = fid => (tnAdj[fid] || []).filter(a => seen[a.partner] && a.partner !== fid);

  const seenCount = Object.keys(seen).length;
  const viewKey = current + "|" + phase + "|" + step + "|" + reg;

  // ---------- styles ----------
  const C = { bg: "#FAFAF8", ink: "#1b1a17", mut: "#9a978f", faint: "#c9c6bd", rule: "#e8e6df" };
  const serif = "Georgia, 'Times New Roman', serif";
  const mono = "ui-monospace, 'SF Mono', Menlo, monospace";
  const wrap = { minHeight: "100vh", background: C.bg, color: C.ink, display: "flex", flexDirection: "column", alignItems: "center", padding: "28px 20px 56px", boxSizing: "border-box" };
  const col = { width: "100%", maxWidth: 560, display: "flex", flexDirection: "column", alignItems: "center", textAlign: "center", flex: 1 };
  const label = { fontFamily: mono, fontSize: 11, letterSpacing: "0.16em", textTransform: "uppercase", color: C.mut };
  const claim = { fontFamily: serif, fontSize: 21, lineHeight: 1.5, margin: "18px 0 0", maxWidth: 520 };
  const small = { fontFamily: mono, fontSize: 11.5, color: C.mut, lineHeight: 1.6 };
  const btn = { fontFamily: mono, fontSize: 12, letterSpacing: "0.06em", padding: "11px 26px", borderRadius: 999, border: "1px solid " + C.ink, background: "transparent", color: C.ink, cursor: "pointer", marginTop: 30 };
  const linkBtn = { fontFamily: mono, fontSize: 11.5, color: C.mut, background: "none", border: "none", cursor: "pointer", letterSpacing: "0.04em" };

  function Slider(onCommit, priorMark) {
    return (
      <div style={{ width: "100%", maxWidth: 380, marginTop: 26 }}>
        <div style={{ fontFamily: serif, fontSize: 40, lineHeight: 1 }}>{slider}<span style={{ fontSize: 18, color: C.mut }}>%</span></div>
        {priorMark != null && <div style={{ ...small, marginTop: 4 }}>you arrived at {Math.round(priorMark * 100)}%</div>}
        <input type="range" min="0" max="100" value={slider} onChange={e => setSlider(+e.target.value)} className="bue-range" style={{ width: "100%", marginTop: 18 }} />
        <div style={{ display: "flex", justifyContent: "space-between", ...label, fontSize: 10 }}>
          <span>certainly false</span><span>certainly true</span>
        </div>
        <button className="bue-btn" style={btn} onClick={onCommit}>Continue</button>
      </div>
    );
  }

  function Finding(f) {
    const fired = firedFor(f.finding_id);
    return (
      <>
        <div style={{ ...label, color: DIR_COLOR[f.direction], display: "flex", gap: 8, justifyContent: "center", alignItems: "center" }}>
          <span style={{ width: 6, height: 6, borderRadius: 6, background: DIR_COLOR[f.direction], display: "inline-block" }} />
          {DIR_LABEL[f.direction]} · {f.evidence_type} · {f.source_strength}
        </div>
        <p style={claim}>{P(f.claim_paragraph)}</p>
        {P(f.effect_size) && P(f.effect_size) !== "qualitative" && <div style={{ ...small, marginTop: 12 }}>{P(f.effect_size)}</div>}
        <div style={{ ...small, fontStyle: "italic", marginTop: 12, maxWidth: 460 }}>{P(f.caveat)}</div>
        <div style={{ ...small, marginTop: 10, color: C.faint }}>{f.source_citation}</div>
        {fired.map((t, i) => (
          <div key={i} style={{ marginTop: 22, paddingTop: 16, borderTop: "1px solid " + C.rule, maxWidth: 460 }}>
            <div style={{ ...label, color: C.ink }}>tension · {t.kind}</div>
            <div style={{ fontFamily: serif, fontSize: 15, lineHeight: 1.5, marginTop: 8, color: "#444" }}>{P(t.note)}</div>
          </div>
        ))}
        <button className="bue-btn" style={btn} onClick={next}>{step < ordered.length - 1 ? "Next" : (node.scored ? "Rate again" : "So it depends →")}</button>
      </>
    );
  }

  function Heading() {
    if (node.role === "topic") return null;
    if (node.scored) return (
      <>
        <div style={{ ...small, marginBottom: 6 }}>{P(node.question)}</div>
        <div style={{ fontFamily: serif, fontSize: 23, lineHeight: 1.45, maxWidth: 520 }}>{P(node.claim_evaluated)}</div>
      </>
    );
    return <div style={{ fontFamily: serif, fontSize: 23, lineHeight: 1.45, maxWidth: 520 }}>{P(node.question)}</div>;
  }

  // ---------- body per phase ----------
  let body;
  if (phase === "reading") {
    body = <>
      {current === "n_root" && step === 0 && (
        <div style={{ marginBottom: 26 }}>
          <div style={{ fontFamily: serif, fontSize: 26, lineHeight: 1.35, maxWidth: 480 }}>A place to test a belief against the evidence.</div>
          <div style={{ ...small, marginTop: 16, maxWidth: 440, lineHeight: 1.7 }}>It won't hand you a verdict. It shows what the research says, where it's thin, and where it pulls in different directions — you do the believing.</div>
          <div style={{ ...small, marginTop: 16, maxWidth: 440, color: C.faint }}>Leaves out: housing, public-service load, gains to employers, origin-country effects, politics. Absence is scope, not proof of no effect.</div>
        </div>
      )}
      {current !== "n_root" && Heading()}
      <div style={{ height: 14 }} />
      {ordered[step] && Finding(ordered[step])}
    </>;
  } else if (phase === "depend") {
    const opts = node.children || [];
    const exploredN = opts.filter(cid => visited[cid]).length;
    body = <>
      {Heading()}
      <div style={{ ...label, marginTop: 30 }}>It depends. On what?</div>
      <div style={{ ...small, marginTop: 6 }}>Pick the aspect that matters most to you — the choice itself is telling.</div>
      {exploredN > 0 && <div style={{ ...small, marginTop: 4, color: C.faint }}>You've explored {exploredN} of {opts.length}.</div>}
      <div style={{ marginTop: 22, width: "100%", maxWidth: 460 }}>
        {opts.map(cid => {
          const vis = !!visited[cid];
          const post = conf[cid] && conf[cid].posterior;
          const tag = vis ? (post != null ? "visited · you left it at " + Math.round(post * 100) + "%" : "visited") : null;
          return (
            <button key={cid} className={"bue-choice" + (vis ? " bue-visited" : "")} onClick={() => chooseChild(cid)}>
              <span>
                <span className="bue-qtext">{P(nodeById[cid].question)}</span>
                {nodeById[cid].evidence_quality === "thin" && <span style={{ ...label, display: "block", marginTop: 5, color: C.faint }}>empirically thin</span>}
                {tag && <span className="bue-visited-tag">{tag}</span>}
              </span>
              <span className="bue-arrow">{vis ? "↺" : "→"}</span>
            </button>
          );
        })}
      </div>
    </>;
  } else if (phase === "teaser") {
    body = <>
      <div style={{ ...label }}>before you narrow</div>
      <div style={{ fontFamily: serif, fontSize: 21, lineHeight: 1.5, marginTop: 16, maxWidth: 500 }}>
        What you've seen pulls against evidence you're about to leave behind.
      </div>
      {teasers.map((t, i) => (
        <div key={i} style={{ marginTop: 20, maxWidth: 460 }}>
          <div style={{ ...label, color: C.ink }}>under → {crumb(nodeById[t.sibling], reg)}</div>
          <div style={{ fontFamily: serif, fontSize: 15, lineHeight: 1.5, marginTop: 8, color: "#444" }}>{P(t.note)}</div>
        </div>
      ))}
      <div style={{ ...small, marginTop: 22 }}>You can come back to it later — nothing you've read is lost.</div>
      <button className="bue-btn" style={btn} onClick={() => enter(pendingChild, [...path, pendingChild])}>Continue →</button>
    </>;
  } else if (phase === "prior") {
    body = <>
      {Heading()}
      <div style={{ ...label, marginTop: 28 }}>before the evidence</div>
      <div style={{ ...small, marginTop: 6 }}>How true does this feel right now?</div>
      {Slider(() => { setConf(c => ({ ...c, [current]: { ...(c[current] || {}), prior: slider / 100 } })); setPhase("reading"); setStep(0); })}
    </>;
  } else if (phase === "posterior") {
    body = <>
      {Heading()}
      <div style={{ ...label, marginTop: 28 }}>now, having read it</div>
      {Slider(() => { setConf(c => ({ ...c, [current]: { ...(c[current] || {}), posterior: slider / 100 } })); setPhase("stop"); }, conf[current]?.prior)}
    </>;
  } else if (phase === "stop") {
    const c = conf[current] || {};
    const d = c.posterior != null && c.prior != null ? Math.round((c.posterior - c.prior) * 100) : null;
    const seenHere = (findingsByNode[current] || []).map(f => f.finding_id);
    const tens = [];
    seenHere.forEach(fid => firedFor(fid).forEach(t => tens.push(t)));
    const uniqT = [...new Map(tens.map(t => [P(t.note), t])).values()];
    const parentFork = [...path].reverse().find(id => !nodeById[id].scored);
    const depObj = node.depends_on;
    const isLeafStop = depObj && (depObj.research || "").startsWith("LEAF");
    body = <>
      {Heading()}
      <div style={{ marginTop: 26, paddingTop: 20, borderTop: "1px solid " + C.rule, maxWidth: 480 }}>
        <div style={{ ...label }}>where the research runs out</div>
        <div style={{ fontFamily: serif, fontSize: 16, lineHeight: 1.6, marginTop: 12, color: "#3a3a36" }}>
          {isLeafStop
            ? P(depObj).replace(/^LEAF:\s*/, "")
            : "This is the edge of what the evidence settles. What's left is a judgment about how much weight to give each piece — a values question, not an empirical one."}
        </div>
      </div>
      {d != null && (
        <div style={{ marginTop: 24 }}>
          <div style={{ ...label }}>your move</div>
          <div style={{ fontFamily: serif, fontSize: 22, marginTop: 8 }}>
            {Math.round(c.prior * 100)}% <span style={{ color: C.mut }}>→</span> {Math.round(c.posterior * 100)}%
          </div>
          <div style={{ ...small, marginTop: 4 }}>{d === 0 ? "held steady" : (d > 0 ? "+" : "") + d + " points"}</div>
        </div>
      )}
      {uniqT.length > 0 && (
        <div style={{ marginTop: 24, maxWidth: 460 }}>
          <div style={{ ...label }}>still unresolved</div>
          {uniqT.map((t, i) => <div key={i} style={{ fontFamily: serif, fontSize: 14.5, lineHeight: 1.5, marginTop: 10, color: "#555" }}>{P(t.note)}</div>)}
        </div>
      )}
      <div style={{ marginTop: 30, display: "flex", gap: 22 }}>
        {parentFork && parentFork !== current &&
          <button className="bue-link" onClick={() => { const i = path.indexOf(parentFork); enter(parentFork, path.slice(0, i + 1)); }}>← explore another branch</button>}
      </div>
    </>;
  }

  return (
    <div style={wrap}>
      <style>{`
        @keyframes bueEnter { from { opacity: 0; transform: translateY(12px); } to { opacity: 1; transform: none; } }
        .bue-fade { animation: bueEnter .44s cubic-bezier(.2,.7,.2,1) both; }
        @media (prefers-reduced-motion: reduce) { .bue-fade { animation: none; } }
        .bue-range { -webkit-appearance: none; appearance: none; height: 2px; background: ${C.faint}; outline: none; border-radius: 2px; }
        .bue-range::-webkit-slider-thumb { -webkit-appearance: none; width: 18px; height: 18px; border-radius: 50%; background: ${C.ink}; cursor: pointer; }
        .bue-range::-moz-range-thumb { width: 18px; height: 18px; border: none; border-radius: 50%; background: ${C.ink}; cursor: pointer; }
        .bue-crumb { text-decoration: underline; text-underline-offset: 2px; text-decoration-style: dotted; text-decoration-color: ${C.faint}; }
        .bue-crumb:hover { color: ${C.ink} !important; text-decoration-color: ${C.ink}; }
        .bue-crumb.bue-current { text-decoration: none; cursor: default; }
        .bue-btn { transition: background .15s, color .15s; }
        .bue-btn:hover { background: ${C.ink}; color: ${C.bg}; }
        .bue-link { color: ${C.ink}; background: none; border: none; padding: 0; cursor: pointer; font-family: ${mono}; font-size: 11.5px; letter-spacing: .04em; text-decoration: underline; text-underline-offset: 3px; }
        .bue-link:hover { opacity: .6; }
        .bue-choice { display: flex; align-items: center; justify-content: center; gap: 12px; width: 100%; box-sizing: border-box; text-align: center; background: #ffffff; border: 1px solid ${C.rule}; border-radius: 12px; padding: 16px 18px; margin-top: 10px; cursor: pointer; font-family: ${serif}; font-size: 17px; color: ${C.ink}; line-height: 1.4; transition: border-color .15s, background .15s, box-shadow .15s; }
        .bue-choice:hover { border-color: ${C.ink}; box-shadow: 0 1px 0 ${C.ink}; }
        .bue-choice .bue-arrow { color: ${C.mut}; font-family: ${mono}; font-size: 13px; }
        .bue-choice:hover .bue-arrow { color: ${C.ink}; }
        .bue-choice.bue-visited { background: #f2f3f6; border-color: #dcdde6; }
        .bue-choice.bue-visited .bue-qtext { color: ${C.mut}; }
        .bue-choice.bue-visited:hover { border-color: #6a6f86; box-shadow: 0 1px 0 #6a6f86; }
        .bue-visited-tag { display: block; margin-top: 6px; font-family: ${mono}; font-size: 10px; letter-spacing: .12em; text-transform: uppercase; color: #6a6f86; }
        .bue-seg { display: inline-flex; border: 1px solid ${C.rule}; border-radius: 999px; overflow: hidden; }
        .bue-seg button { font-family: ${mono}; font-size: 10.5px; letter-spacing: .08em; text-transform: uppercase; padding: 5px 13px; background: none; border: none; cursor: pointer; color: ${C.mut}; transition: background .15s, color .15s; }
        .bue-seg button:hover { color: ${C.ink}; }
        .bue-seg button.bue-on { background: ${C.ink}; color: ${C.bg}; }
      `}</style>

      {/* language toggle */}
      <div style={{ width: "100%", maxWidth: 560, display: "flex", justifyContent: "center", alignItems: "center", gap: 10, marginBottom: 18 }}>
        <span style={{ ...label, fontSize: 10, color: C.faint }}>language</span>
        <div className="bue-seg">
          {[["research", "Research"], ["simple", "Plain"]].map(([k, lab]) => (
            <button key={k} className={reg === k ? "bue-on" : ""} onClick={() => setReg(k)}>{lab}</button>
          ))}
        </div>
      </div>

      {/* breadcrumb */}
      <div style={{ width: "100%", maxWidth: 560, display: "flex", justifyContent: "center", flexWrap: "wrap", gap: 6, marginBottom: 30 }}>
        {path.map((id, i) => (
          <span key={id} style={{ ...label, fontSize: 10.5 }}>
            {i > 0 && <span style={{ color: C.faint, margin: "0 6px" }}>{"›"}</span>}
            <button className={"bue-crumb" + (i === path.length - 1 ? " bue-current" : "")}
              onClick={() => { if (i !== path.length - 1) enter(id, path.slice(0, i + 1)); }}
              style={{ background: "none", border: "none", padding: 0, cursor: "pointer", color: i === path.length - 1 ? C.ink : C.mut, ...label, fontSize: 10.5 }}>
              {crumb(nodeById[id], reg)}
            </button>
          </span>
        ))}
      </div>

      <div style={col}>
        <div key={viewKey} className="bue-fade" style={{ display: "flex", flexDirection: "column", alignItems: "center", width: "100%" }}>
          {body}
        </div>
      </div>

      <div style={{ ...label, fontSize: 10, color: C.faint, marginTop: 40 }}>{seenCount} of {DATA.findings.length} findings seen</div>
    </div>
  );
}
